 63→var createCmd = &cobra.Command{
 64→	Use:     "create [name]",
 65→	Aliases: []string{"cr"},
 66→	Short:   "Create a new sandbox",
 67→	Long: `Create a new sandbox.
 68→
 69→If no name is provided, creates a temporary sandbox with an auto-generated name like "temp-<timestamp>".
 70→
 71→Environment variables can set defaults for commonly used flags:
 72→  SANDCASTLE_HOME=1    equivalent to --home
 73→  SANDCASTLE_DATA=.    equivalent to --data (value is the subpath, "." or "1" for root)
 74→  SANDCASTLE_RM=1      equivalent to --rm
 75→
 76→Flags explicitly passed on the command line take precedence over environment variables.`,
 77→	Args: cobra.MaximumNArgs(1),
 78→	PreRun: func(cmd *cobra.Command, args []string) {
 79→		// Priority: explicit flag > env var > config preference
 80→		cfg, _ := config.Load()
 81→		prefs := cfg.LoadPreferences()
 82→
 83→		if !cmd.Flags().Changed("home") {
 84→			if prefs.MountHome != nil && *prefs.MountHome {
 85→				sandboxHome = true
 86→			}
 87→		}
 88→		if !cmd.Flags().Changed("rm") && envTruthy("SANDCASTLE_RM") {
 89→			sandboxRemove = true
 90→		}
 91→		if !cmd.Flags().Changed("data") {
 92→			if prefs.DataPath != "" {
 93→				sandboxData = prefs.DataPath
 94→			}
 95→		}
 96→	},
 97→	RunE: func(cmd *cobra.Command, args []string) error {
 98→		client, err := api.NewClient()
 99→		if err != nil {
100→			return err
101→		}
102→		printServer(client)
103→
104→		// Auto-generate name if not provided
105→		var name string
106→		autoGenerated := false
107→		if len(args) == 0 {
108→			name = fmt.Sprintf("temp-%d", time.Now().Unix())
109→			autoGenerated = true
110→			// Auto-generated sandboxes are temporary by default
111→			if !cmd.Flags().Changed("rm") {
112→				sandboxRemove = true
113→			}
114→		} else {
115→			name = args[0]
116→		}
117→
118→		// Resolve snapshot flags: --from-snapshot takes precedence over --snapshot
119→		fromSnap := sandboxFromSnapshot
120→		if fromSnap == "" {
121→			fromSnap = sandboxSnapshot
122→		}
123→
124→		var restoreLayers []string
125→		if sandboxRestoreLayers != "" {
126→			for _, l := range strings.Split(sandboxRestoreLayers, ",") {
127→				restoreLayers = append(restoreLayers, strings.TrimSpace(l))
128→			}
129→		}
130→
131→		sandbox, err := client.CreateSandbox(api.CreateSandboxRequest{
132→			Name:          name,
133→			Image:         sandboxImage,
134→			Persistent:    sandboxPersistent,
135→			FromSnapshot:  fromSnap,
136→			RestoreLayers: restoreLayers,
137→			Tailscale:     sandboxTailscale,
138→			MountHome:     sandboxHome,
139→			DataPath:      sandboxData,
140→			Temporary:     sandboxRemove,
141→			VNCEnabled:    !sandboxNoVNC,
142→			VNCGeometry:   sandboxVNCGeometry,
143→			VNCDepth:      sandboxVNCDepth,
144→		})
145→		if err != nil {
146→			return err
147→		}
148→
149→		if autoGenerated {
150→			fmt.Printf("Sandbox %q created (auto-generated name).\n", sandbox.Name)
151→		} else {
152→			fmt.Printf("Sandbox %q created.\n", sandbox.Name)
153→		}
154→
155→		// Print active options (use local flags — they reflect what was actually requested)
156→		if sandboxHome || sandboxData != "" || sandboxPersistent || sandbox.Tailscale || sandboxRemove || fromSnap != "" || sandboxNoVNC || sandboxVNCGeometry != "" || sandboxVNCDepth != 0 {
157→			if sandboxHome {
158→				fmt.Println("  Home:      mounted (~/ persisted)")
159→			}
160→			if sandboxData != "" {
161→				label := sandboxData
162→				if label == "." {
163→					label = "user data root"
164→				}
165→				fmt.Printf("  Data:      mounted (%s → /data)\n", label)
166→			}
167→			if sandboxPersistent {
168→				fmt.Println("  Volume:    persistent (/workspace)")
169→			}
170→			if sandbox.Tailscale {
171→				fmt.Println("  Tailscale: enabled")
172→			}
173→			if sandboxRemove {
174→				fmt.Println("  Cleanup:   auto-remove on exit")
175→			}
176→			if fromSnap != "" {
177→				fmt.Printf("  Snapshot:  restored from %q\n", fromSnap)
178→			}
179→			if sandboxNoVNC {
180→				fmt.Println("  VNC:       disabled")
181→			} else if sandboxVNCGeometry != "" || sandboxVNCDepth != 0 {
182→				geom := sandbox.VNCGeometry
183→				if geom == "" {
184→					geom = "1280x900"
185→				}
186→				depth := sandbox.VNCDepth
187→				if depth == 0 {
188→					depth = 24
189→				}
190→				fmt.Printf("  VNC:       %s @ %d-bit\n", geom, depth)
191→			}
192→		}
193→
194→		if sandboxNoConnect {
195→			return nil
196→		}
197→
198→		info, err := client.ConnectInfo(sandbox.ID)
199→		if err != nil {
200→			return err
201→		}
202→
203→		if os.Getenv("VERBOSE") == "1" {
204→			fmt.Fprintf(os.Stderr, "\033[2m[verbose] Connection info: host=%s port=%d user=%s\033[0m\n", info.Host, info.Port, info.User)
205→			if info.TailscaleIP != "" {
206→				fmt.Fprintf(os.Stderr, "\033[2m[verbose] Tailscale IP (Tailscale): %s\033[0m\n", info.TailscaleIP)
207→			}
208→		}
209→
210→		if err := waitForSSH(info.Host, info.Port); err != nil {
211→			return err
212→		}
213→
214→		cfg, loadErr := config.Load()
215→		if loadErr != nil {
216→			return loadErr
217→		}
218→		prefs := cfg.LoadPreferences()
219→
220→		var remoteCmd string
221→		if *prefs.UseTmux {
222→			remoteCmd = "tmux new-session -A -s main"
223→		}
224→
225→		var sshErr error
226→		if pickProtocol(cfg, info.Host, info.Port, info.User, prefs.SSHExtraArgs) == "mosh" {
227→			sshErr = moshExec(info.Host, info.Port, info.User, remoteCmd, prefs.SSHExtraArgs)
228→		} else {
229→			sshErr = sshExec(info.Host, info.Port, info.User, remoteCmd, prefs.SSHExtraArgs)
230→		}
231→
232→		if sandboxRemove {
233→			// Re-fetch to check if user toggled to "keep" during the session
234→			current, fetchErr := client.GetSandbox(sandbox.ID)
235→			if fetchErr == nil && !current.Temporary {
236→				fmt.Printf("Sandbox %q was set to keep — skipping removal.\n", sandbox.Name)
237→			} else {
238→				fmt.Printf("Removing sandbox %q...\n", sandbox.Name)
239→				if err := client.DestroySandbox(sandbox.ID); err != nil {
240→					fmt.Fprintf(os.Stderr, "Warning: failed to delete sandbox: %v\n", err)
241→				} else {
242→					fmt.Printf("Sandbox %q deleted.\n", sandbox.Name)
243→				}
244→			}
245→		}
246→
247→		return sshErr
248→	},
249→}
