251→var listCmd = &cobra.Command{
252→	Use:     "list",
253→	Aliases: []string{"ls"},
254→	Short:   "List all sandboxes",
255→	RunE: func(cmd *cobra.Command, args []string) error {
256→		client, err := api.NewClient()
257→		if err != nil {
258→			return err
259→		}
260→		printServer(client)
261→
262→		if listArchived {
263→			sandboxes, err := client.ListArchivedSandboxes()
264→			if err != nil {
265→				return err
266→			}
267→			if len(sandboxes) == 0 {
268→				fmt.Println("No archived sandboxes.")
269→				return nil
270→			}
271→			w := tabwriter.NewWriter(os.Stdout, 0, 0, 2, ' ', 0)
272→			fmt.Fprintln(w, "ID\tNAME\tARCHIVED\tCREATED\tIMAGE")
273→			for _, s := range sandboxes {
274→				archivedAt := ""
275→				if s.ArchivedAt != nil {
276→					archivedAt = s.ArchivedAt.Local().Format("2006-01-02 15:04")
277→				}
278→				created := s.CreatedAt.Local().Format("2006-01-02 15:04")
279→				fmt.Fprintf(w, "%d\t%s\t%s\t%s\t%s\n", s.ID, s.Name, archivedAt, created, s.Image)
280→			}
281→			w.Flush()
282→			return nil
283→		}
284→
285→		sandboxes, err := client.ListSandboxes()
286→		if err != nil {
287→			return err
288→		}
289→
290→		if len(sandboxes) == 0 {
291→			fmt.Println("No sandboxes.")
292→			return nil
293→		}
294→
295→		hasRoute := false
296→		for _, s := range sandboxes {
297→			if len(s.Routes) > 0 {
298→				hasRoute = true
299→				break
300→			}
301→		}
302→
303→		w := tabwriter.NewWriter(os.Stdout, 0, 0, 2, ' ', 0)
304→		if hasRoute {
305→			fmt.Fprintln(w, "NAME\tSTATUS\tCREATED\tROUTE\tTAILSCALE IP\tIMAGE")
306→		} else {
307→			fmt.Fprintln(w, "NAME\tSTATUS\tCREATED\tTAILSCALE IP\tIMAGE")
308→		}
309→		for _, s := range sandboxes {
310→			name := s.Name
311→			if s.Temporary {
312→				name += " (temp)"
313→			}
314→			tsIP := ""
315→			if s.TailscaleIP != "" {
316→				tsIP = s.TailscaleIP
317→			}
318→			created := s.CreatedAt.Local().Format("2006-01-02 15:04")
319→			if hasRoute {
320→				route := ""
321→				if len(s.Routes) > 0 {
322→					parts := make([]string, len(s.Routes))
323→					for i, r := range s.Routes {
324→						parts[i] = fmt.Sprintf("%s (:%d)", r.URL, r.Port)
325→					}
326→					route = strings.Join(parts, ", ")
327→				}
328→				fmt.Fprintf(w, "%s\t%s\t%s\t%s\t%s\t%s\n", name, s.Status, created, route, tsIP, s.Image)
329→			} else {
330→				fmt.Fprintf(w, "%s\t%s\t%s\t%s\t%s\n", name, s.Status, created, tsIP, s.Image)
331→			}
332→		}
333→		w.Flush()
334→		return nil
335→	},
336→}
