446→var useCmd = &cobra.Command{
447→	Use:   "use [name]",
448→	Short: "Show or set active server/sandbox",
449→	Long: `Without arguments, shows the current server and active sandbox.
450→With an argument, switches the active server or sandbox.
451→
452→Examples:
453→  sandcastle use                  # Show current server and sandbox
454→  sandcastle use my-sandbox       # Set active sandbox
455→  sandcastle use prod             # Switch to server "prod" (if configured)`,
456→	Args: cobra.MaximumNArgs(1),
457→	RunE: func(cmd *cobra.Command, args []string) error {
458→		cfg, err := config.Load()
459→		if err != nil {
460→			return err
461→		}
462→
463→		// No args: list all servers, highlight active
464→		if len(args) == 0 {
465→			if len(cfg.Servers) == 0 {
466→				fmt.Println("No servers configured — run: sandcastle login <url>")
467→				return nil
468→			}
469→
470→			aliases := make([]string, 0, len(cfg.Servers))
471→			for alias := range cfg.Servers {
472→				aliases = append(aliases, alias)
473→			}
474→			sort.Strings(aliases)
475→
476→			for _, alias := range aliases {
477→				srv := cfg.Servers[alias]
478→				if alias == cfg.CurrentServer {
479→					fmt.Printf("  \033[1m* %-16s\033[0m %s\n", alias, srv.URL)
480→				} else {
481→					fmt.Printf("    %-16s %s\n", alias, srv.URL)
482→				}
483→			}
484→
485→			return nil
486→		}
487→
488→		name := args[0]
489→
490→		// Check if name matches a server alias or URL
491→		if _, ok := cfg.Servers[name]; ok {
492→			cfg.CurrentServer = name
493→			if err := config.Save(cfg); err != nil {
494→				return err
495→			}
496→			fmt.Printf("Switched to server %s (%s)\n", name, cfg.Servers[name].URL)
497→			return nil
498→		}
499→
500→		// Try matching by URL
501→		for alias, srv := range cfg.Servers {
502→			if srv.URL == strings.TrimRight(name, "/") {
503→				cfg.CurrentServer = alias
504→				if err := config.Save(cfg); err != nil {
505→					return err
506→				}
507→				fmt.Printf("Switched to server %s (%s)\n", alias, srv.URL)
508→				return nil
509→			}
510→		}
511→
512→		return fmt.Errorf("server %q not found — run: sandcastle use", name)
513→	},
514→}
