516→var setCmd = &cobra.Command{
517→	Use:   "set <name> <temp|keep>",
518→	Short: "Toggle sandbox between temporary and kept",
519→	Long: `Toggle a sandbox between temporary (auto-remove on exit) and kept.
520→
521→  temp   Mark as temporary — will be removed when the CLI session exits
522→  keep   Mark as kept — will not be auto-removed`,
523→	Args: cobra.ExactArgs(2),
524→	RunE: func(cmd *cobra.Command, args []string) error {
525→		client, err := api.NewClient()
526→		if err != nil {
527→			return err
528→		}
529→		printServer(client)
530→
531→		sandbox, err := findSandboxByName(client, args[0])
532→		if err != nil {
533→			return err
534→		}
535→
536→		mode := strings.ToLower(args[1])
537→		var temp bool
538→		switch mode {
539→		case "temp":
540→			temp = true
541→		case "keep":
542→			temp = false
543→		default:
544→			return fmt.Errorf("unknown mode %q: use \"temp\" or \"keep\"", args[1])
545→		}
546→
547→		sandbox, err = client.UpdateSandbox(sandbox.ID, api.UpdateSandboxRequest{Temporary: &temp})
548→		if err != nil {
549→			return err
550→		}
551→
552→		if temp {
553→			fmt.Printf("Sandbox %q set to temporary (will be removed on exit).\n", sandbox.Name)
554→		} else {
555→			fmt.Printf("Sandbox %q set to keep (will not be removed on exit).\n", sandbox.Name)
556→		}
557→		return nil
558→	},
559→}
