589→func envTruthy(key string) bool {
590→	v := strings.ToLower(os.Getenv(key))
591→	return v == "1" || v == "true" || v == "yes"
592→}
593→
594→func findSandboxByName(client *api.Client, name string) (*api.Sandbox, error) {
595→	sandboxes, err := client.ListSandboxes()
596→	if err != nil {
597→		return nil, err
598→	}
599→	for _, s := range sandboxes {
600→		if s.Name == name {
601→			return &s, nil
602→		}
603→	}
604→	return nil, fmt.Errorf("sandbox %q not found", name)
