223→func (c *Client) PollDeviceToken(deviceCode string) (token string, pending bool, err error) {
224→	status, body, err := c.doWithStatus("POST", "/api/auth/device_token", DeviceTokenRequest{DeviceCode: deviceCode})
225→	if err != nil {
226→		return "", false, err
227→	}
228→
229→	switch status {
230→	case 200:
231→		var resp DeviceTokenResponse
232→		if err := json.Unmarshal(body, &resp); err != nil {
233→			return "", false, fmt.Errorf("parsing response: %w", err)
234→		}
235→		return resp.Token, false, nil
236→	case 428: // Precondition Required — authorization_pending
237→		return "", true, nil
238→	default:
239→		var apiErr APIError
240→		if json.Unmarshal(body, &apiErr) == nil && apiErr.Error != "" {
241→			return "", false, fmt.Errorf("%s", apiErr.Error)
242→		}
243→		return "", false, fmt.Errorf("unexpected status %d: %s", status, string(body))
244→	}
245→}
