237→			} else {
238→				fmt.Printf("Removing sandbox %q...\n", sandbox.Name)
239→				if err := client.DestroySandbox(sandbox.ID); err != nil {
240→					fmt.Fprintf(os.Stderr, "Warning: failed to delete sandbox: %v\n", err)
241→				} else {
242→					fmt.Printf("Sandbox %q deleted.\n", sandbox.Name)
243→				}
244→			}
245→		}
246→
