108→
109→func (c *Client) do(method, path string, body any, result any) error {
110→	var bodyReader io.Reader
111→	var reqData []byte
112→	if body != nil {
113→		var err error
114→		reqData, err = json.Marshal(body)
115→		if err != nil {
116→			return fmt.Errorf("marshaling request: %w", err)
117→		}
118→		bodyReader = bytes.NewReader(reqData)
119→	}
120→
121→	logVerbose("→ %s %s%s", method, c.BaseURL, path)
122→	if len(reqData) > 0 {
123→		logVerbose("  request: %s", string(reqData))
124→	}
125→
126→	req, err := http.NewRequest(method, c.BaseURL+path, bodyReader)
127→	if err != nil {
128→		return fmt.Errorf("creating request: %w", err)
129→	}
130→
131→	req.Header.Set("Content-Type", "application/json")
132→	if c.Token != "" {
133→		req.Header.Set("Authorization", "Bearer "+c.Token)
134→	}
135→
136→	resp, err := c.HTTPClient.Do(req)
137→	if err != nil {
138→		return fmt.Errorf("request failed: %w", err)
139→	}
140→	defer resp.Body.Close()
141→
142→	respBody, err := io.ReadAll(resp.Body)
143→	if err != nil {
144→		return fmt.Errorf("reading response: %w", err)
145→	}
146→
147→	logVerbose("← %d (%d bytes)", resp.StatusCode, len(respBody))
148→	if len(respBody) > 0 {
149→		logVerbose("  response: %s", string(respBody))
150→	}
151→
152→	if resp.StatusCode >= 400 {
153→		var apiErr APIError
154→		if json.Unmarshal(respBody, &apiErr) == nil && apiErr.Error != "" {
155→			return fmt.Errorf("API error (%d): %s", resp.StatusCode, apiErr.Error)
156→		}
157→		return fmt.Errorf("API error (%d): %s", resp.StatusCode, string(respBody))
158→	}
159→
160→	if result != nil {
161→		if err := json.Unmarshal(respBody, result); err != nil {
162→			return fmt.Errorf("parsing response: %w", err)
163→		}
164→	}
165→	return nil
166→}
167→
168→// doWithStatus is like do but returns the HTTP status code along with the response body.
169→func (c *Client) doWithStatus(method, path string, body any) (int, []byte, error) {
170→	var bodyReader io.Reader
171→	var reqData []byte
172→	if body != nil {
173→		var err error
174→		reqData, err = json.Marshal(body)
175→		if err != nil {
176→			return 0, nil, fmt.Errorf("marshaling request: %w", err)
177→		}
178→		bodyReader = bytes.NewReader(reqData)
179→	}
180→
181→	logVerbose("→ %s %s%s", method, c.BaseURL, path)
182→	if len(reqData) > 0 {
183→		logVerbose("  request: %s", string(reqData))
184→	}
185→
186→	req, err := http.NewRequest(method, c.BaseURL+path, bodyReader)
187→	if err != nil {
188→		return 0, nil, fmt.Errorf("creating request: %w", err)
189→	}
190→
191→	req.Header.Set("Content-Type", "application/json")
192→	if c.Token != "" {
193→		req.Header.Set("Authorization", "Bearer "+c.Token)
194→	}
195→
196→	resp, err := c.HTTPClient.Do(req)
197→	if err != nil {
198→		return 0, nil, fmt.Errorf("request failed: %w", err)
199→	}
200→	defer resp.Body.Close()
201→
202→	respBody, err := io.ReadAll(resp.Body)
203→	if err != nil {
204→		return 0, nil, fmt.Errorf("reading response: %w", err)
205→	}
206→
207→	logVerbose("← %d (%d bytes)", resp.StatusCode, len(respBody))
208→	if len(respBody) > 0 {
209→		logVerbose("  response: %s", string(respBody))
210→	}
211→
212→	return resp.StatusCode, respBody, nil
213→}
