  1→package config
  2→
  3→import (
  4→	"fmt"
  5→	"os"
  6→	"path/filepath"
  7→	"strings"
  8→
  9→	"gopkg.in/yaml.v3"
 10→)
 11→
 12→type ServerConfig struct {
 13→	URL      string `yaml:"url"`
 14→	Token    string `yaml:"token"`
 15→	Insecure bool   `yaml:"insecure,omitempty"`
 16→}
 17→
 18→// Preferences holds user-configurable CLI behaviour. Each field can be
 19→// overridden by a SANDCASTLE_<KEY> environment variable at runtime.
 20→type Preferences struct {
 21→	ConnectProtocol string `yaml:"connect_protocol,omitempty"` // "ssh" (default) | "mosh"
 22→	UseTmux         *bool  `yaml:"use_tmux,omitempty"`         // default true
 23→	SSHExtraArgs    string `yaml:"ssh_extra_args,omitempty"`   // extra flags for ssh/mosh
 24→	MountHome       *bool  `yaml:"mount_home,omitempty"`       // default false; --home on create
 25→	DataPath        string `yaml:"data_path,omitempty"`        // default ""; --data on create
 26→}
 27→
 28→type Config struct {
 29→	CurrentServer string                  `yaml:"current_server"`
 30→	Servers       map[string]ServerConfig `yaml:"servers"`
 31→	Preferences   Preferences             `yaml:"preferences,omitempty"`
 32→}
 33→
 34→// legacyConfig is the old flat format for migration.
 35→type legacyConfig struct {
 36→	Server string `yaml:"server"`
 37→	Token  string `yaml:"token"`
 38→}
 39→
 40→func Dir() string {
 41→	home, _ := os.UserHomeDir()
 42→	return filepath.Join(home, ".sandcastle")
 43→}
 44→
 45→func Path() string {
 46→	return filepath.Join(Dir(), "config.yaml")
 47→}
 48→
 49→func Load() (*Config, error) {
 50→	cfg := &Config{Servers: make(map[string]ServerConfig)}
 51→	data, err := os.ReadFile(Path())
 52→	if err != nil {
 53→		if os.IsNotExist(err) {
 54→			return cfg, nil
 55→		}
 56→		return nil, fmt.Errorf("reading config: %w", err)
 57→	}
 58→
 59→	// Try new format first
 60→	if err := yaml.Unmarshal(data, cfg); err != nil {
 61→		return nil, fmt.Errorf("parsing config: %w", err)
 62→	}
 63→
 64→	// Migrate legacy flat format
 65→	if cfg.Servers == nil || len(cfg.Servers) == 0 {
 66→		var legacy legacyConfig
 67→		if err := yaml.Unmarshal(data, &legacy); err == nil && legacy.Server != "" {
 68→			cfg.Servers = map[string]ServerConfig{
 69→				"default": {URL: legacy.Server, Token: legacy.Token},
 70→			}
 71→			cfg.CurrentServer = "default"
 72→			// Save migrated config
 73→			_ = Save(cfg)
 74→		}
 75→	}
 76→
 77→	if cfg.Servers == nil {
 78→		cfg.Servers = make(map[string]ServerConfig)
 79→	}
 80→
 81→	return cfg, nil
 82→}
 83→
 84→func Save(cfg *Config) error {
 85→	if err := os.MkdirAll(Dir(), 0o700); err != nil {
 86→		return fmt.Errorf("creating config dir: %w", err)
 87→	}
 88→	data, err := yaml.Marshal(cfg)
 89→	if err != nil {
 90→		return fmt.Errorf("marshaling config: %w", err)
 91→	}
 92→	if err := os.WriteFile(Path(), data, 0o600); err != nil {
 93→		return fmt.Errorf("writing config: %w", err)
 94→	}
 95→	return nil
 96→}
 97→
 98→// CurrentServerConfig returns the active server's URL and token.
 99→func (c *Config) CurrentServerConfig() (ServerConfig, error) {
100→	if c.CurrentServer == "" {
101→		return ServerConfig{}, fmt.Errorf("no server configured — run: sandcastle login <url>")
102→	}
103→	srv, ok := c.Servers[c.CurrentServer]
104→	if !ok {
105→		return ServerConfig{}, fmt.Errorf("server %q not found in config — run: sandcastle login <url>", c.CurrentServer)
106→	}
107→	return srv, nil
108→}
109→
110→// SetServer adds or updates a server and sets it as current.
111→func (c *Config) SetServer(alias, url, token string, insecure bool) {
112→	if c.Servers == nil {
113→		c.Servers = make(map[string]ServerConfig)
114→	}
115→	c.Servers[alias] = ServerConfig{URL: url, Token: token, Insecure: insecure}
116→	c.CurrentServer = alias
117→}
118→
119→// LoadPreferences returns effective preferences with env vars overlaid.
120→// Priority: ENV var > config file preference > built-in default.
121→func (c *Config) LoadPreferences() Preferences {
122→	p := c.Preferences
123→
124→	if v := os.Getenv("SANDCASTLE_CONNECT_PROTOCOL"); v != "" {
125→		p.ConnectProtocol = v
126→	}
127→	if v := os.Getenv("SANDCASTLE_USE_TMUX"); v != "" {
128→		b := strings.ToLower(v) == "true" || v == "1"
129→		p.UseTmux = &b
130→	}
131→	if v := os.Getenv("SANDCASTLE_SSH_EXTRA_ARGS"); v != "" {
132→		p.SSHExtraArgs = v
133→	}
134→	if v := os.Getenv("SANDCASTLE_HOME"); v != "" {
135→		b := strings.ToLower(v) == "true" || v == "1"
136→		p.MountHome = &b
137→	}
138→	if v := os.Getenv("SANDCASTLE_DATA"); v != "" {
139→		if v == "1" || v == "true" {
140→			v = "."
141→		}
142→		p.DataPath = v
143→	}
144→
145→	// Apply built-in defaults
146→	if p.ConnectProtocol == "" {
147→		p.ConnectProtocol = "ssh"
148→	}
149→	if p.UseTmux == nil {
150→		t := true
151→		p.UseTmux = &t
152→	}
153→
154→	return p
155→}
156→
157→// SetPreference sets a named preference by string value and validates it.
158→func (c *Config) SetPreference(key, value string) error {
159→	switch key {
160→	case "connect_protocol":
161→		if value != "ssh" && value != "mosh" && value != "auto" {
162→			return fmt.Errorf("connect_protocol must be 'ssh', 'mosh', or 'auto', got %q", value)
163→		}
164→		if value == "auto" {
165→			c.Preferences.ConnectProtocol = ""
166→		} else {
167→			c.Preferences.ConnectProtocol = value
168→		}
169→	case "use_tmux":
170→		switch strings.ToLower(value) {
171→		case "true", "1", "yes":
172→			t := true
173→			c.Preferences.UseTmux = &t
174→		case "false", "0", "no":
175→			f := false
176→			c.Preferences.UseTmux = &f
177→		default:
178→			return fmt.Errorf("use_tmux must be 'true' or 'false', got %q", value)
179→		}
180→	case "ssh_extra_args":
181→		c.Preferences.SSHExtraArgs = value
182→	case "mount_home":
183→		switch strings.ToLower(value) {
184→		case "true", "1", "yes":
185→			t := true
186→			c.Preferences.MountHome = &t
187→		case "false", "0", "no":
188→			f := false
189→			c.Preferences.MountHome = &f
190→		default:
191→			return fmt.Errorf("mount_home must be 'true' or 'false', got %q", value)
192→		}
193→	case "data_path":
194→		if value == "false" || value == "0" || value == "no" || value == "off" {
195→			c.Preferences.DataPath = ""
196→		} else {
197→			if value == "true" || value == "1" {
198→				value = "."
199→			}
200→			c.Preferences.DataPath = value
201→		}
202→	default:
203→		return fmt.Errorf("unknown preference %q; valid keys: connect_protocol, use_tmux, ssh_extra_args, mount_home, data_path", key)
204→	}
205→	return nil
206→}
