		printServer(client)

		// Auto-generate name if not provided
		var name string
		autoGenerated := false
		if len(args) == 0 {
			name = fmt.Sprintf("temp-%d", time.Now().Unix())
			autoGenerated = true
			// Auto-generated sandboxes are temporary by default
			if !cmd.Flags().Changed("rm") {
				sandboxRemove = true
			}
		} else {
			name = args[0]
		}

		// Resolve snapshot flags: --from-snapshot takes precedence over --snapshot
		fromSnap := sandboxFromSnapshot
		if fromSnap == "" {
			fromSnap = sandboxSnapshot
		}

		var restoreLayers []string
		if sandboxRestoreLayers != "" {
			for _, l := range strings.Split(sandboxRestoreLayers, ",") {
				restoreLayers = append(restoreLayers, strings.TrimSpace(l))
			}
		}

		sandbox, err := client.CreateSandbox(api.CreateSandboxRequest{
			Name:          name,
			Image:         sandboxImage,
			Persistent:    sandboxPersistent,
			FromSnapshot:  fromSnap,
			RestoreLayers: restoreLayers,
			Tailscale:     sandboxTailscale,
			MountHome:     sandboxHome,
			DataPath:      sandboxData,
			Temporary:     sandboxRemove,
			VNCEnabled:    !sandboxNoVNC,
			VNCGeometry:   sandboxVNCGeometry,
			VNCDepth:      sandboxVNCDepth,
		})
		if err != nil {
			return err
		}

		if autoGenerated {
			fmt.Printf("Sandbox %q created (auto-generated name).\n", sandbox.Name)
		} else {
			fmt.Printf("Sandbox %q created.\n", sandbox.Name)
		}

		// Print active options (use local flags — they reflect what was actually requested)
		if sandboxHome || sandboxData != "" || sandboxPersistent || sandbox.Tailscale || sandboxRemove || fromSnap != "" || sandboxNoVNC || sandboxVNCGeometry != "" || sandboxVNCDepth != 0 {
			if sandboxHome {
				fmt.Println("  Home:      mounted (~/ persisted)")
			}
			if sandboxData != "" {
				label := sandboxData
				if label == "." {
					label = "user data root"
				}
				fmt.Printf("  Data:      mounted (%s → /data)\n", label)
			}
			if sandboxPersistent {
				fmt.Println("  Volume:    persistent (/workspace)")
			}
			if sandbox.Tailscale {
				fmt.Println("  Tailscale: enabled")
			}
			if sandboxRemove {
				fmt.Println("  Cleanup:   auto-remove on exit")
			}
			if fromSnap != "" {
				fmt.Printf("  Snapshot:  restored from %q\n", fromSnap)
			}
			if sandboxNoVNC {
				fmt.Println("  VNC:       disabled")
			} else if sandboxVNCGeometry != "" || sandboxVNCDepth != 0 {
				geom := sandbox.VNCGeometry
				if geom == "" {
					geom = "1280x900"
				}
				depth := sandbox.VNCDepth
				if depth == 0 {
					depth = 24
				}
				fmt.Printf("  VNC:       %s @ %d-bit\n", geom, depth)
			}
		}

		if sandboxNoConnect {
			return nil
		}

		info, err := client.ConnectInfo(sandbox.ID)
		if err != nil {
			return err
		}

		if os.Getenv("VERBOSE") == "1" {
			fmt.Fprintf(os.Stderr, "\033[2m[verbose] Connection info: host=%s port=%d user=%s\033[0m\n", info.Host, info.Port, info.User)
			if info.TailscaleIP != "" {
				fmt.Fprintf(os.Stderr, "\033[2m[verbose] Tailscale IP (Tailscale): %s\033[0m\n", info.TailscaleIP)
			}
		}

		if err := waitForSSH(info.Host, info.Port); err != nil {
			return err
		}

		cfg, loadErr := config.Load()
		if loadErr != nil {
			return loadErr
		}
		prefs := cfg.LoadPreferences()

		var remoteCmd string
		if *prefs.UseTmux {
			remoteCmd = "tmux new-session -A -s main"
		}

		var sshErr error
		if pickProtocol(cfg, info.Host, info.Port, info.User, prefs.SSHExtraArgs) == "mosh" {
			sshErr = moshExec(info.Host, info.Port, info.User, remoteCmd, prefs.SSHExtraArgs)
		} else {
			sshErr = sshExec(info.Host, info.Port, info.User, remoteCmd, prefs.SSHExtraArgs)
		}

		if sandboxRemove {
			// Re-fetch to check if user toggled to "keep" during the session
			current, fetchErr := client.GetSandbox(sandbox.ID)
			if fetchErr == nil && !current.Temporary {
				fmt.Printf("Sandbox %q was set to keep — skipping removal.\n", sandbox.Name)
			} else {
				fmt.Printf("Removing sandbox %q...\n", sandbox.Name)
				if err := client.DestroySandbox(sandbox.ID); err != nil {
					fmt.Fprintf(os.Stderr, "Warning: failed to delete sandbox: %v\n", err)
				} else {
					fmt.Printf("Sandbox %q deleted.\n", sandbox.Name)
				}
			}
		}

		return sshErr
	},
}

var listCmd = &cobra.Command{
	Use:     "list",
	Aliases: []string{"ls"},
	Short:   "List all sandboxes",
	RunE: func(cmd *cobra.Command, args []string) error {
		client, err := api.NewClient()
		if err != nil {
			return err
		}
		printServer(client)

		if listArchived {
			sandboxes, err := client.ListArchivedSandboxes()
			if err != nil {
				return err
			}
			if len(sandboxes) == 0 {
				fmt.Println("No archived sandboxes.")
				return nil
			}
			w := tabwriter.NewWriter(os.Stdout, 0, 0, 2, ' ', 0)
			fmt.Fprintln(w, "ID\tNAME\tARCHIVED\tCREATED\tIMAGE")
			for _, s := range sandboxes {
				archivedAt := ""
				if s.ArchivedAt != nil {
					archivedAt = s.ArchivedAt.Local().Format("2006-01-02 15:04")
				}
				created := s.CreatedAt.Local().Format("2006-01-02 15:04")
				fmt.Fprintf(w, "%d\t%s\t%s\t%s\t%s\n", s.ID, s.Name, archivedAt, created, s.Image)
			}
			w.Flush()
			return nil
		}

		sandboxes, err := client.ListSandboxes()
		if err != nil {
			return err
		}

		if len(sandboxes) == 0 {
			fmt.Println("No sandboxes.")
			return nil
		}

		hasRoute := false
		for _, s := range sandboxes {
			if len(s.Routes) > 0 {
				hasRoute = true
				break
			}
		}

		w := tabwriter.NewWriter(os.Stdout, 0, 0, 2, ' ', 0)
		if hasRoute {
			fmt.Fprintln(w, "NAME\tSTATUS\tCREATED\tROUTE\tTAILSCALE IP\tIMAGE")
		} else {
			fmt.Fprintln(w, "NAME\tSTATUS\tCREATED\tTAILSCALE IP\tIMAGE")
		}
		for _, s := range sandboxes {
			name := s.Name
			if s.Temporary {
				name += " (temp)"
			}
			tsIP := ""
			if s.TailscaleIP != "" {
				tsIP = s.TailscaleIP
			}
			created := s.CreatedAt.Local().Format("2006-01-02 15:04")
			if hasRoute {
				route := ""
				if len(s.Routes) > 0 {
					parts := make([]string, len(s.Routes))
					for i, r := range s.Routes {
						parts[i] = fmt.Sprintf("%s (:%d)", r.URL, r.Port)
					}
					route = strings.Join(parts, ", ")
				}
				fmt.Fprintf(w, "%s\t%s\t%s\t%s\t%s\t%s\n", name, s.Status, created, route, tsIP, s.Image)
			} else {
				fmt.Fprintf(w, "%s\t%s\t%s\t%s\t%s\n", name, s.Status, created, tsIP, s.Image)
			}
		}
		w.Flush()
		return nil
	},
}

