					route = strings.Join(parts, ", ")
				}
				fmt.Fprintf(w, "%s\t%s\t%s\t%s\t%s\t%s\n", name, s.Status, created, route, tsIP, s.Image)
			} else {
				fmt.Fprintf(w, "%s\t%s\t%s\t%s\t%s\n", name, s.Status, created, tsIP, s.Image)
			}
		}
		w.Flush()
		return nil
	},
}

